{"code": "import os
import subprocess
from hermes_tools import terminal, read_file

def try_read_file(filepath):
    """Try to read a file using various methods"""
    print(f"\n=== Trying to read: {filepath} ===")

    # First check if it exists and get file info
    result = terminal(f"file -b '{filepath}'")
    print(f"File type: {result.get('output', '').strip()}")

    result = terminal(f"ls -lh '{filepath}'")
    print(f"File size: {result.get('output', '').strip()}")

    # Try different reading methods based on file extension
    ext = os.path.splitext(filepath)[1].lower()

    if ext in ['.txt', '.md', '.csv', '.json', '.xml', '.html', '.htm']:
        # Try direct read_file for text files
        try:
            content = read_file(filepath, offset=1, limit=50)
            print(f"First 50 lines (via read_file):")
            print(content.get('content', '')[:2000])
        except Exception as e:
            print(f"read_file failed: {e}")

    elif ext in ['.doc', '.docx', '.rtf']:
        # Try textutil for macOS to convert to text
        try:
            result = terminal(f"textutil -convert txt -stdout '{filepath}' 2>/dev/null | head -100")
            if result.get('output', '').strip():
                print(f"Text extracted (first 100 lines via textutil):")
                print(result.get('output', '')[:2000])
            else:
                # Try strings command as fallback
                result = terminal(f"strings '{filepath}' | head -50")
                if result.get('output', '').strip():
                    print(f"Text extracted (first 50 strings):")
                    print(result.get('output', '')[:2000])
                else:
                    print("Could not extract text")
        except Exception as e:
            print(f"Error extracting text: {e}")

    elif ext == '.pdf':
        # Try pdftotext if available
        try:
            result = terminal(f"which pdftotext")
            if result.get('output', '').strip():
                result = terminal(f"pdftotext '{filepath}' - 2>/dev/null | head -100")
                if result.get('output', '').strip():
                    print(f"PDF text (first 100 lines via pdftotext):")
                    print(result.get('output', '')[:2000])
                else:
                    # Try strings as fallback
                    result = terminal(f"strings '{filepath}' | head -50")
                    if result.get('output', '').strip():
                        print(f"PDF strings (first 50):")
                        print(result.get('output', '')[:2000])
                    else:
                        print("Could not extract PDF text")
            else:
                print("pdftotext not available, trying strings...")
                result = terminal(f"strings '{filepath}' | head -50")
                if result.get('output', '').strip():
                    print(f"PDF strings (first 50):")
                    print(result.get('output', '')[:2000])
                else:
                    print("Could not extract PDF text")
        except Exception as e:
            print(f"Error extracting PDF: {e}")

    else:
        print(f"Unsupported file type: {ext}")

# Key files to read
key_files = [
    # Company and qualification documents
    "/Users/东盛工作/0资质办理/000资质办理标准/工程设计资质.pdf",
    "/Users/东盛工作/0资质办理/人才合同/注册师注册说明文件.doc",

    # Project cooperation methods
    "/Users/东盛工作/21安全性鉴定/项目合作办法.docx",

    # Safety assessment report
    "/Users/东盛工作/21安全性鉴定/11.04原岷化金矿投资修建的1#学生公寓楼结构安全性鉴定.pdf",

    # Village introduction documents
    "/Users/东盛工作/27西和乡村局/各村基础数据/1村情简介-席川村.doc",

    # Business calculation
    "/Users/东盛工作/24麦积区鉴定/业务计算-天水市麦积区.xlsx"
]

# Try to read each file
for i, filepath in enumerate(key_files):
    if i > 0:
        print("\n" + "="*80 + "\n")
    try_read_file(filepath)"}
